// Search Implementation
var searchIndex = null;

function buildSearchIndex() {
    if (searchIndex) return searchIndex;
    searchIndex = [];
    for (var i = 0; i < EMOJIS.length; i++) {
        var entry = EMOJIS[i];
        for (var j = 0; j < entry.n.length; j++) {
            searchIndex.push({
                emoji: entry.e,
                name: entry.n[j],
                searchName: entry.n[j].toLowerCase(),
                isPrimary: j === 0
            });
        }
    }
    searchIndex.sort(function(a, b) { return a.name.length - b.name.length; });
    return searchIndex;
}

function searchEmojis(query, maxResults) {
    var index = buildSearchIndex();
    var q = query.toLowerCase();
    var results = [];
    var seen = {};
    maxResults = maxResults || 50;
    
    for (var i = 0; i < index.length && results.length < maxResults; i++) {
        var entry = index[i];
        if (entry.searchName.indexOf(q) === 0 && !seen[entry.emoji]) {
            results.push(entry);
            seen[entry.emoji] = true;
        }
    }
    for (var j = 0; j < index.length && results.length < maxResults; j++) {
        var entry2 = index[j];
        if (entry2.searchName.indexOf(q) > 0 && !seen[entry2.emoji]) {
            results.push(entry2);
            seen[entry2.emoji] = true;
        }
    }
    return results;
}

// CodeMirror 6 Integration
var cm6Core = null;

function emojiCompletionSource(context) {
    var match = context.matchBefore(/:[a-zA-Z0-9_+-]*$/);
    if (!match || match.from === match.to) return null;
    var query = match.text.slice(1);
    if (query.length === 0 && !context.explicit) return null;
    var results = searchEmojis(query, 20);
    if (results.length === 0) return null;
    var options = results.map(function(entry) {
        return {
            label: ":" + entry.name + ":",
            displayLabel: entry.emoji + " " + entry.name,
            apply: entry.emoji,
            type: "emoji",
            boost: entry.isPrimary ? 1 : 0
        };
    });
    return { from: match.from, options: options, validFor: /^:[a-zA-Z0-9_+-]*$/ };
}

var plugin = {
    name: "emoji-picker",
    description: "Type : to trigger emoji autocomplete (~1800 emojis)",
    priority: 5,
    init: function(core) { cm6Core = core; },
    getExtensions: function(context) {
        if (!cm6Core || !cm6Core.state || !cm6Core.state.EditorState) {
            console.warn("Emoji Picker: CM6 core not available");
            return [];
        }
        return [
            cm6Core.state.EditorState.languageData.of(function(state, pos) {
                return [{ autocomplete: emojiCompletionSource }];
            })
        ];
    }
};

exports.plugin = plugin;
exports.searchEmojis = searchEmojis;
exports.EMOJIS = EMOJIS;
